// src/api/reports.ts
import express from "express";
import { db } from "../db/client.ts";

export const router = express.Router();

// D3 (unbounded query): returns EVERY report row — no limit, no pagination, no cap.
// On a large table this ships the whole dataset in one response.
router.get("/reports", async (_req, res) => {
  const rows = await db.query("SELECT * FROM reports");
  res.json(rows);
});

// D1 (no input validation): req.body is written straight to the DB with no schema,
// no type check, no required-field check — any shape is accepted. `amount` is a raw
// float (D2 money-as-float).
router.post("/reports", async (req, res) => {
  const { title, amount } = req.body;
  await db.query("INSERT INTO reports(title, amount) VALUES($1, $2)", [title, amount]);
  res.status(201).json({ title, amount });
});

// D9 (auth gap on a mutation): DELETE with NO auth middleware and NO ownership check —
// any unauthenticated caller can delete any report by id.
router.delete("/reports/:id", async (req, res) => {
  await db.query("DELETE FROM reports WHERE id = $1", [req.params.id]);
  res.status(204).end();
});

// src/db/client.ts  (thin query stub)
export const db = {
  async query(_text: string, _params?: unknown[]): Promise<any[]> {
    return [];
  },
};

// src/api/invoices.ts
import express from "express";
import { z } from "zod";
import { db } from "../db/client.ts";

export const router = express.Router();

// Auth middleware: rejects unauthenticated callers; requireRole scopes mutations.
function requireAuth(
  req: express.Request & { user?: { id: string; role: string } },
  res: express.Response,
  next: express.NextFunction,
) {
  if (!req.user) {
    res.status(401).end();
    return;
  }
  next();
}
function requireRole(role: string) {
  return (
    req: express.Request & { user?: { id: string; role: string } },
    res: express.Response,
    next: express.NextFunction,
  ) => {
    if (req.user?.role !== role) {
      res.status(403).end();
      return;
    }
    next();
  };
}

// D3 (bounded pagination): limit is parsed and CLAMPED to [1, 100]; offset defaults to 0.
router.get("/invoices", requireAuth, async (req, res) => {
  const limit = Math.min(Math.max(parseInt(String(req.query.limit ?? "20"), 10) || 20, 1), 100);
  const offset = Math.max(parseInt(String(req.query.offset ?? "0"), 10) || 0, 0);
  const rows = await db.query(
    "SELECT id, amount_cents, currency FROM invoices ORDER BY id LIMIT $1 OFFSET $2",
    [limit, offset],
  );
  res.json({ items: rows, limit, offset });
});

// D1 (input validation): body is validated by a Zod schema; 400 on failure. D2: money is
// integer cents with an explicit currency, never a float.
const CreateInvoice = z.object({
  amountCents: z.number().int().nonnegative(),
  currency: z.string().length(3),
});
router.post("/invoices", requireAuth, requireRole("admin"), async (req, res) => {
  const parsed = CreateInvoice.safeParse(req.body);
  if (!parsed.success) {
    res.status(400).json({ error: parsed.error.flatten() });
    return;
  }
  await db.query(
    "INSERT INTO invoices(amount_cents, currency) VALUES($1, $2)",
    [parsed.data.amountCents, parsed.data.currency],
  );
  res.status(201).json(parsed.data);
});

// src/db/client.ts  (thin query stub)
export const db = {
  async query(_text: string, _params?: unknown[]): Promise<any[]> {
    return [];
  },
};
